API_name: nchu_course_search_by_teaching_method
Description:
{
  "description": "Search courses by teaching method. Common teaching methods: 講授, 討論, 習作, 實習, 實驗, 專題, 報告, 演講, etc. JSON string containing courses using the specified teaching method",
  "required_parameters": [
    {
      "name": "method",
      "type": "STRING",
      "description": "Teaching method to search for (e.g., 實習, 討論, 專題)"
    }
  ],
  "optional_parameters": [
    {
      "name": "limit",
      "type": "NUMBER",
      "description": "Maximum number of results to return (default: 20)",
      "default": 20
    },
    {
      "name": "semester",
      "type": "STRING",
      "description": "Semester code. If not specified, uses the latest semester.",
      "default": null
    }
  ]
}

